-- Enrichment marathon batch: Twilio, Twingate, Twist, Tyk, Typebot, Typedream, Typeface, Typeform

-- ── Twilio ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Twilio is a cloud communications platform that lets developers embed voice calls, SMS, WhatsApp messaging, video, and email into applications through simple APIs.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free trial credit; pay-as-you-go from $0.0083 per SMS$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$5,001-10,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Twilio Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See Twilio's usage-based pricing, API features, and how the leading cloud communications platform for SMS, voice, and email compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Twilio is a publicly traded cloud communications platform (NYSE: TWLO) founded in March 2008 by Jeff Lawson, Evan Cooke, and John Wolthuis, headquartered in San Francisco, California. It provides developer-first APIs that let software teams embed SMS, voice calling, WhatsApp messaging, email, video, and identity verification into their own applications instead of building telecom infrastructure from scratch. Twilio's core products include Programmable Messaging, Programmable Voice, Verify (OTP and two-factor authentication), Lookup, the SendGrid Email API (acquired 2019), the Conversations API for omnichannel messaging orchestration, and Segment, the customer data platform Twilio acquired in 2020. Twilio pioneered usage-based pricing for telecom APIs: developers pay per message, per minute, or per verification rather than signing carrier contracts, with rates starting around $0.0083 per SMS and $0.0085 per minute of inbound voice. The company went public in 2016, serves hundreds of thousands of businesses including Airbnb, Uber, Lyft, and Netflix, and reported roughly $5.3 billion in trailing twelve-month revenue with about 5,600 employees and a market capitalization near $28.6 billion as of mid-2026. Key differentiators are its mature documentation and SDK coverage across nearly every programming language, direct carrier relationships spanning 100+ countries, and its evolution from pure communications APIs into a broader customer engagement stack combining messaging, customer data (Segment), and AI-assisted conversation intelligence. Competitors include Vonage (Nexmo), Bird (formerly MessageBird), Plivo, Sinch, and Amazon SNS/Pinpoint for narrower use cases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c884a739-077a-42ee-961b-611a66af1052';

