-- ── Tyk ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tyk is an open source and enterprise API gateway and management platform for building, securing, and scaling REST, GraphQL, TCP, and gRPC APIs.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source Gateway); paid Cloud/Self-Managed tiers usage-based or custom$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$London, England, UK$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tyk Review 2026: API Gateway Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Tyk offers an open source and enterprise API gateway. See pricing tiers, key features, and how it compares to other API management platforms.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tyk is an API gateway and full lifecycle API management platform founded in London in 2014 by Martin Buhr, who wrote the original open source gateway as a personal project before turning it into a company; Tyk Technologies Limited is headquartered in London, England, with regional offices including Atlanta and Singapore. The core Tyk Gateway, written in Go, is fully open source under the Mozilla Public License 2.0 and free to self-host indefinitely, supporting REST, GraphQL, TCP, and gRPC protocols with no mandatory third-party dependencies aside from Redis for rate-limiting and token storage. On top of the free gateway, Tyk sells a commercial API management platform, Tyk Self-Managed and Tyk Cloud, that adds a management control plane, a dashboard GUI, and a developer portal, sold through three tiers: Core (consumption-based pricing for startups), Professional (flat-rate pricing with unlimited APIs and requests for scaling teams), and Enterprise (custom pricing with advanced governance, multi-region and multi-cloud support, and named customer success managers). Tyk has raised approximately $35 million in a 2021 funding round and reports powering digital infrastructure for banks, retailers, and telcos across more than 100 markets, with customers including NatWest, SoundCloud, Zeiss, T-Mobile, Dollar General, AXA, Cisco, TripAdvisor, and USA Today, claiming to support over 100 million people's financial transactions daily. Tyk differentiates itself from cloud-native gateways like AWS API Gateway and from competitors such as Kong and Apigee by combining a genuinely free, unrestricted open source core with a full commercial API management suite, appealing to teams that want to avoid vendor lock-in while still getting enterprise governance, developer portals, and support when needed.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '89dff1be-8908-47b5-b669-4283360cd267';

