-- ── Typebot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Typebot is a visual, open source chatbot and conversational form builder that can be self-hosted or used as a cloud service, letting teams design chat flows without code.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (200 chats/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Chatou, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Typebot Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See Typebot's pricing plans, chatbot builder features, and self-hosting options for this open source conversational form tool.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Typebot is a visual chatbot and conversational form builder founded in 2020 by French solo developer Baptiste Arnaud, based in Chatou, France, and built as a bootstrapped, largely one-person product before growing into a small team. It lets non-developers and developers alike design chat flows using a drag-and-drop editor with more than 40 building blocks, including text and media bubbles, input fields, buttons, date pickers, payment inputs, and logic branches, then embed the resulting chatbot on a website, mobile app, or as a standalone link. Typebot's code is source-available under the Functional Source License, and the project can be fully self-hosted for free by deploying it from its GitHub repository, or used as a managed cloud service with tiered subscription pricing. Cloud pricing includes a free Personal plan with 200 chats per month and unlimited typebots, a Starter plan at $39 per month for 2,000 chats with branding removal and file uploads, a Pro plan at $89 per month for 10,000 chats with WhatsApp integration and custom domains, and a custom-quoted Enterprise plan with SSO, dedicated IP, and ISO 27001 compliance support. Typebot integrates natively with tools like Google Sheets, Zapier, Make, and webhooks, and supports custom JavaScript and CSS for advanced customization. It competes with tools like Landbot, Chatfuel, ManyChat, and Voiceflow, but differentiates itself through its open source, self-hostable core and its focus on both marketing chatbots and structured conversational data collection forms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a1d7d4b6-0a0c-446a-a22f-7046fe96be45';

