-- ── Typedream ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Typedream is a no-code, AI-assisted website builder for creators and small businesses, acquired by newsletter platform beehiiv in 2024.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Typedream Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Typedream is a no-code AI website builder now owned by beehiiv. See pricing plans, features, and how it compares to Webflow and Notion sites.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Typedream is a no-code website builder founded in 2020 by Kevin Chandra, Anthony Christian, Putri Karunia, Michelle Marcelline, and Albert Purnama, and backed by Y Combinator (Winter 2020 batch); the company was headquartered in San Francisco, California. It positions itself as combining the simplicity of building a page in Notion with the polished visual output of a tool like Webflow, using a drag-and-drop block editor, pre-designed templates, and AI-assisted content and layout generation to let creators, solopreneurs, and small businesses launch websites, landing pages, and digital product storefronts without code. On June 26, 2024, Typedream was acquired by beehiiv, the newsletter and publishing platform, which folded Typedream's website-building technology into its own product to give beehiiv publishers more flexible, AI-assisted website tools alongside their newsletters; typedream.com continues to operate as a standalone product. Typedream's pricing is freemium and tiered: a free plan covers one page on a typedream.app subdomain with a Typedream badge, the Launch plan costs $15 per month billed annually (or $20 month-to-month) and adds unlimited pages, custom domains, SEO tools, code injection, analytics, and one blog with 1,000 form submissions, and the Grow plan costs $42 per month billed annually (or $49 month-to-month) and adds unlimited blogs, unlimited form submissions, password protection, up to five collaborators, and email marketing for up to 5,000 subscribers. Typedream competes with website builders like Carrd, Webflow, Notion-based site tools, and Framer, differentiated by its acquisition-driven integration with beehiiv's newsletter and publishing ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c98b6563-0ec6-441b-b5ed-0beb5d47e8f7';

