-- ── Typeface ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Typeface is an enterprise generative AI platform for creating on-brand marketing, sales, and creative content at scale, founded by former Adobe CTO Abhay Parasnis.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (contact sales)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Typeface AI Review 2026: Features, Pricing and Funding$q$, seo_title),
  seo_meta_description = COALESCE($q$Typeface is an enterprise generative AI content platform. See its features, funding history, and how it compares to other AI content tools.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Typeface is an enterprise generative AI content platform founded in 2022 by Abhay Parasnis, a former Adobe CTO, along with Vishal Sood and Tran Anh, headquartered in San Francisco, California. The platform lets marketing, sales, and creative teams generate on-brand text, images, and campaign assets at scale by training on a company's brand guidelines, tone, and visual identity, then producing personalized content across channels while keeping outputs consistent with brand standards. Typeface emerged from stealth in February 2023 with an oversubscribed $65 million funding round backed by Lightspeed Venture Partners, GV (Google Ventures), M12 (Microsoft's venture fund), and Menlo Ventures, notable for having both Google and Microsoft as investors in the same AI company. In June 2023, Typeface closed a $100 million Series B led by Salesforce Ventures, bringing total funding to roughly $206 million at a valuation of about $1 billion. The company positions its platform as agentic and enterprise-grade, integrating with tools like Salesforce Marketing Cloud and Microsoft's ecosystem, and emphasizes data governance, brand safety, and IP-indemnified outputs as differentiators against more general-purpose AI writing and image tools. Typeface does not publish detailed self-serve pricing; access is primarily sold through custom, sales-assisted enterprise contracts with tiers reportedly built around Team, Business, and Enterprise use, and the company reports roughly $34 million in estimated annual recurring revenue as of 2025. Competitors and comparable tools include Jasper, Writer, Adobe Firefly for enterprise, and Persado, all targeting brand-consistent AI content generation for large organizations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '123b8401-6f03-436d-a3b8-572de129cfec';

