-- ── Typeform ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Typeform is an online form and survey builder known for its conversational, one-question-at-a-time interface used for lead generation, surveys, and quizzes.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (10 responses/month)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$501-1,000 employees$q$, company_size),
  headquarters = COALESCE($q$Barcelona, Spain$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$]::text[],
  seo_title = COALESCE($q$Typeform Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$See Typeform's pricing plans, response limits, and features for building conversational forms, surveys, and quizzes.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Typeform is an online form and survey builder founded in 2012 by Robert Munoz and David Okuniev, headquartered in Barcelona, Spain, with an additional office in San Francisco, California. It popularized a conversational, one-question-at-a-time interface for online forms, replacing traditional long, all-at-once form layouts with a more engaging, animated experience designed to improve completion rates for surveys, lead generation forms, quizzes, and feedback collection. Typeform operates on a freemium subscription model: the free plan allows up to 10 responses per month across all forms combined, a limit Typeform reduced from 100 per month in early 2026. Paid plans scale from the Basic plan at $28 per month billed annually (100 responses/month, 1 user) through Plus ($56/month, 1,000 responses, 3 users) and Business ($91/month, 10,000 responses, 5 users, drop-off analysis, priority support), plus specialized Talent ($119/month) and Growth Flow ($266/month) plans aimed at recruiting and lead-enrichment use cases respectively, and a custom-priced Enterprise plan with unlimited responses, SSO, and HIPAA/GDPR compliance support. The company has raised approximately $187 million in total funding and reported roughly $141 million in estimated annual recurring revenue with a valuation near $935 million as of 2024, and employs several hundred people globally. Typeform's key differentiators are its distinctive conversational UX, AI-assisted form creation, and integrations with tools like Salesforce, HubSpot, and Google Sheets, competing with form and survey tools such as Google Forms, SurveyMonkey, Jotform, and Tally.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bb9a5203-561f-405b-883a-bf1a1d13b0fd';

