INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$What is Typebot used for?$q$, $q$Typebot is used to build chatbots and conversational forms for lead generation, customer support, surveys, and structured data collection.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Is Typebot free?$q$, $q$Typebot's cloud plan has a free tier with 200 chats per month, and the underlying software is open source and free to self-host.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Who created Typebot?$q$, $q$Typebot was created in 2020 by Baptiste Arnaud, a solo developer based in Chatou, France.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Can I self-host Typebot?$q$, $q$Yes, Typebot's source code is publicly available on GitHub and can be self-hosted for free on your own infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$How much does Typebot's cloud plan cost?$q$, $q$Paid cloud plans start at $39 per month for 2,000 chats (Starter) and $89 per month for 10,000 chats (Pro), with custom Enterprise pricing above that.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Does Typebot support WhatsApp?$q$, $q$Yes, WhatsApp deployment is available on the Pro and Enterprise plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$What license is Typebot released under?$q$, $q$Typebot's source code is available under the Functional Source License.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$What are alternatives to Typebot?$q$, $q$Common alternatives include Landbot, Chatfuel, ManyChat, and Voiceflow.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Lead generation chat forms$q$, $q$Marketing teams replace static web forms with conversational Typebot flows to improve completion rates.$q$, $q$Marketing and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Customer support triage bots$q$, $q$Support teams build Typebot flows to collect information and route customers before human handoff.$q$, $q$Customer support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Self-hosted internal tools$q$, $q$Engineering teams self-host Typebot to build internal data collection or onboarding flows with full data control.$q$, $q$Engineering and IT teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Personal (Free)$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["200 chats/month","Unlimited typebots","Native integrations and webhooks","Custom JavaScript and CSS","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Starter$q$, $q$$39/month$q$, $q$monthly$q$, NULL, $q$["2,000 chats/month","2 seats included","Branding removal","File uploads and folders","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Pro$q$, $q$$89/month$q$, $q$monthly$q$, NULL, $q$["10,000 chats/month","5 seats included","WhatsApp integration","Custom domains","In-depth analytics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$Enterprise$q$, $q$Custom pricing$q$, $q$custom$q$, NULL, $q$["Custom chat and seat limits","SLA contracts","24/7 dedicated support","SSO and granular access rights","ISO 27001 compliance support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$overview$q$, $q$What Is Typebot$q$, 2, ARRAY[$q$Typebot is a visual chatbot and conversational form builder that lets teams design chat-based experiences without writing code, then embed them on websites, mobile apps, or share them as standalone links. It blends the flexibility of a chatbot builder with the structured data collection of a form tool, letting users create multi-step, conditional conversations that feel more natural than a traditional web form.$q$, $q$The project was created in 2020 by Baptiste Arnaud, a solo French developer based in Chatou, France, who built and grew Typebot largely on his own as a bootstrapped, profitable product before it evolved into a small team. Typebot's source code is publicly available on GitHub under the Functional Source License, and the project can be self-hosted for free by anyone comfortable running their own infrastructure, or used through Typebot's managed cloud service.$q$, $q$Typebot is popular with startups, marketers, and no-code builders who want more control and customization than typical chatbot platforms allow, particularly teams that value the ability to self-host for cost savings, data residency, or compliance reasons while still having the option to use a fully managed cloud plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Typebot's visual editor includes more than 40 building blocks for constructing conversations, covering text and media bubbles, various input types like text fields, buttons, date pickers, file uploads, and payment inputs, plus logic blocks for branching, conditions, and variable handling. This lets users build everything from simple lead-capture forms to multi-step qualification flows and customer support bots.$q$, $q$Bots can be deployed as a popup, embedded chat widget, full-page experience, or standalone shareable link, and results are collected in real time with built-in analytics on completion rates and drop-off points. Typebot supports custom JavaScript and CSS for deeper branding and functional customization beyond the visual builder.$q$, $q$The platform integrates natively with tools like Google Sheets, Zapier, Make, and webhooks for connecting to external systems, and paid plans add WhatsApp deployment, custom domains, and more in-depth analytics. Because the underlying code is open source, technical teams can also self-host Typebot entirely on their own infrastructure at no licensing cost.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a1d7d4b6-0a0c-446a-a22f-7046fe96be45', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Typebot's cloud service uses a freemium, usage-based subscription model tied to monthly chat volume. The free Personal plan includes 200 chats per month, unlimited typebots, native integrations, webhooks, and custom JavaScript and CSS, with community support. The Starter plan costs $39 per month for 2,000 chats (with extra chats available at $10 per 500), includes two seats, and adds branding removal, file uploads, folders, and priority support.$q$, $q$The Pro plan costs $89 per month for 10,000 chats, includes five seats, and adds WhatsApp integration, custom domains, and in-depth analytics. An Enterprise plan offers custom chat and seat limits with SLA contracts, 24/7 dedicated support, SSO, granular access rights, a dedicated IP, and ISO 27001 compliance support. All cloud plans bill monthly with no long-term lock-in, and the core software remains free to self-host for teams that prefer to run their own infrastructure.$q$]::text[], 2);
