INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$What is Typedream used for?$q$, $q$Typedream is used to build websites, landing pages, and simple digital product storefronts without writing code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Is Typedream free?$q$, $q$Yes, Typedream offers a free plan limited to one page on a typedream.app subdomain with Typedream branding.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Who owns Typedream now?$q$, $q$Typedream was acquired by beehiiv, the newsletter and publishing platform, on June 26, 2024.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Who founded Typedream?$q$, $q$Typedream was founded in 2020 by Kevin Chandra, Anthony Christian, Putri Karunia, Michelle Marcelline, and Albert Purnama.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$How much does Typedream cost?$q$, $q$Paid plans start at $15 per month billed annually for the Launch plan, up to $42 per month billed annually for the Grow plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Does Typedream support custom domains?$q$, $q$Yes, custom domain support is available starting on the Launch plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Was Typedream part of Y Combinator?$q$, $q$Yes, Typedream went through Y Combinator's Winter 2020 batch.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$What are alternatives to Typedream?$q$, $q$Common alternatives include Carrd, Webflow, Framer, and Notion-based site builders.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Launching a product or newsletter landing page$q$, $q$Creators use Typedream to quickly launch a landing page for a new product, service, or newsletter.$q$, $q$Creators and solopreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Personal portfolios$q$, $q$Freelancers and professionals build portfolio sites without hiring a developer or designer.$q$, $q$Freelancers and independent professionals$q$, 1);
