INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$Grow$q$, $q$$42/month billed annually ($49/month monthly)$q$, $q$annual or monthly$q$, NULL, $q$["Unlimited blogs","Unlimited form submissions","Password protection","Up to 5 collaborators","Email marketing up to 5,000 subscribers"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$overview$q$, $q$What Is Typedream$q$, 2, ARRAY[$q$Typedream is a no-code website builder designed to make launching a polished website as easy as writing a Notion page. It targets creators, solopreneurs, and small businesses who want to build landing pages, portfolios, and simple digital product storefronts without hiring a developer or learning a complex design tool.$q$, $q$The company was founded in 2020 by Kevin Chandra, Anthony Christian, Putri Karunia, Michelle Marcelline, and Albert Purnama, and went through Y Combinator's Winter 2020 batch before establishing itself in San Francisco, California. Typedream built its reputation on combining an extremely simple, block-based editing experience with AI-assisted content and layout generation to speed up the site-building process.$q$, $q$In June 2024, Typedream was acquired by beehiiv, the newsletter and publishing platform, which integrated Typedream's website-building technology into its own product suite to offer beehiiv publishers more flexible website tools alongside their newsletters. Typedream continues to operate its own product and site independently of beehiiv's core newsletter platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Typedream's editor uses a block-based system similar to Notion, where users add and rearrange content blocks like text, images, embeds, and forms directly on the page in a WYSIWYG interface. Pre-designed templates cover common use cases like personal portfolios, product launch pages, and small business sites, giving users a polished starting point.$q$, $q$AI-assisted tools help generate page copy, layout suggestions, and content structure based on a short prompt, reducing the time needed to go from a blank page to a functioning site. Built-in SEO tools let users edit meta titles, descriptions, and site structure without needing separate SEO plugins.$q$, $q$Paid plans add custom domain support, site analytics, code injection for advanced customization, blogging functionality, password-protected pages, and basic email marketing tools for building and messaging a subscriber list, positioning Typedream as a lightweight all-in-one tool for creators who want a site plus simple audience-building features.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Typedream uses a freemium pricing model with three tiers. The Free plan costs $0 per month and supports one page on a typedream.app subdomain with a Typedream badge, limited to a single user, suitable for hobby projects and simple pages.$q$, $q$The Launch plan costs $15 per month billed annually (or $20 per month billed monthly) and is aimed at landing pages and product launches, adding unlimited pages, custom domain support, SEO tools, code injection, site analytics, 1,000 form submissions, and one blog. The Grow plan costs $42 per month billed annually (or $49 per month billed monthly) and is aimed at growing businesses or larger sites, adding unlimited blogs, unlimited form submissions, password protection, up to five collaborators, and email marketing for up to 5,000 subscribers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c98b6563-0ec6-441b-b5ed-0beb5d47e8f7', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
